// Build a clean, normalised payload for the Kian Portal Inbox API.
// Reads from the WEBHOOK node (not the Sheets node) and is SAFE against missing
// fields, non-text message types, and Meta status callbacks. Emits one item per
// real message; emits NOTHING for status events (so the HTTP node won't fire).
const root = $('Webhook').first().json;
const payload = root.body ?? root;              // n8n may nest the POST body under .body
const changes = (payload?.entry || []).flatMap(e => e?.changes || []);
const out = [];
for (const ch of changes) {
  const value = ch?.value || {};
  const contact = (value.contacts || [])[0] || {};
  for (const m of (value.messages || [])) {
    if (!m || !m.id) continue;                  // skip anything without a message id
    const type = m.type || 'text';
    let body = '';
    if (type === 'text') body = m.text?.body || '';
    else if (type === 'button') body = m.button?.text || '';
    else if (type === 'interactive') body = m.interactive?.list_reply?.title || m.interactive?.button_reply?.title || '';
    else if (m.caption) body = m.caption;       // image/video/document captions
    out.push({ json: {
      wa_id:        contact.wa_id || m.from || '',
      phone:        m.from || contact.wa_id || '',
      display_name: contact.profile?.name || '',
      message_id:   m.id,
      message_type: type,
      body:         body,
      timestamp:    m.timestamp || '',
      raw_payload:  payload
    }});
  }
}
return out;
